import{_ as n,o as s,c as l,a2 as i}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 16 章 从收藏资料到可复用知识资产","description":"收藏只是把资料放进一个地方；知识管理要让资料能被找到、理解、核验并再次用于任务。本章讲通用方法，不公开真实知识库目录或内部文档。 形成“原始素材不丢、每项知识有来源、重复内容可合并、不确定内容有标记、知识能够回到具体任务”的体系。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 16 章 收藏不是知识管理，能再次用起来才是/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 16 章 收藏不是知识管理，能再次用起来才是/index.md","lastUpdated":1784100816000}'),e={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 16 章 收藏不是知识管理，能再次用起来才是/index.md"};function t(p,a,o,r,c,h){return s(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="第-16-章-从收藏资料到可复用知识资产" tabindex="-1">第 16 章 从收藏资料到可复用知识资产 <a class="header-anchor" href="#第-16-章-从收藏资料到可复用知识资产" aria-label="Permalink to &quot;第 16 章 从收藏资料到可复用知识资产&quot;">​</a></h1><p>收藏只是把资料放进一个地方；知识管理要让资料能被找到、理解、核验并再次用于任务。本章讲通用方法，不公开真实知识库目录或内部文档。</p><h2 id="可应用到哪些任务" tabindex="-1">可应用到哪些任务 <a class="header-anchor" href="#可应用到哪些任务" aria-label="Permalink to &quot;可应用到哪些任务&quot;">​</a></h2><ul><li>保存政策、行业文章、报告、视频笔记和培训资料。</li><li>为专题工作建立来源页、概念页和分析页。</li><li>从多份材料中提炼可复用方法、模板和问题清单。</li><li>为以后检索、写作和研判保留可靠出处。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>形成“原始素材不丢、每项知识有来源、重复内容可合并、不确定内容有标记、知识能够回到具体任务”的体系。</p><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><ol><li><strong>保留素材层</strong>：原始文件或链接保持不变，记录来源和时间。</li><li><strong>建立来源页</strong>：每项材料记录核心主张、关键细节、可复用方法、个人评注和来源说明。</li><li><strong>提炼知识点</strong>：一个知识点解决一个问题，并链接回来源页。</li><li><strong>建立主题入口</strong>：用主题、任务和状态组织，不只依赖文件夹。</li><li><strong>处理不确定性</strong>：无法核实的内容标记“待核验”，不进入正式结论。</li><li><strong>定期复用与更新</strong>：记录知识被哪个任务使用，过期内容保留历史状态。</li></ol><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>将三篇公开文章整理为“会议待办提取方法”知识卡。每篇文章各有来源页，知识卡引用具体段落，并注明哪些步骤来自来源、哪些是整理者的建议。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把当前目录中的资料整理为可追溯知识条目。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主题：{主题}</span></span>
<span class="line"><span>使用目的：{以后要解决的任务}</span></span>
<span class="line"><span>材料范围：{文件或链接}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每项材料分别输出：</span></span>
<span class="line"><span>1. 核心主张；</span></span>
<span class="line"><span>2. 关键细节；</span></span>
<span class="line"><span>3. 可复用方法；</span></span>
<span class="line"><span>4. 待核验内容；</span></span>
<span class="line"><span>5. 我的评注占位；</span></span>
<span class="line"><span>6. 来源、日期和原文件位置。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不要合并成一个无法追溯的大摘要；不要修改原始材料；</span></span>
<span class="line"><span>重复知识先建立关联，等待确认后再合并。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>来源是否真实、完整并允许保存。</li><li>摘要是否改变原意，评注是否与原文分开。</li><li>重复内容是否真的可以合并。</li><li>敏感材料是否只保留索引，不扩写正文。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>每项来源有独立记录和稳定标识。</li><li>知识点能够回到来源，不是无出处结论。</li><li>待核验、已确认、已过期状态清楚。</li><li>主题入口能回答“这项知识可用于什么任务”。</li></ul><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>大批资料压成一个摘要会失去出处，应一项来源一条记录。</li><li>只收藏不写使用目的，日后仍找不到。每条知识关联任务。</li><li>把宣传包装一起保留会稀释方法，应区分事实、观点和推广内容。</li><li>不公开内部知识目录、不复制敏感原文、不静默修改来源。可复用来源页、知识卡、主题索引和待核验清单。</li></ul>`,18)])])}const b=n(e,[["render",t]]);export{u as __pageData,b as default};
